        [Parameter]
        [Category(CategoryTypes.FormComponent.ListBehavior)]
        public bool SelectionOnEnter { get; set; }

        /// <summary>
        /// Prevents scrolling while the dropdown is open.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.ListBehavior)]
        public bool LockScroll { get; set; }

        /// <summary>
